// AUTO-GENERATED — GrooveLab Genre Backing Tracks Database
  // Tempo-bucketed library: each genre has slow / medium / fast / veryFast lanes.
  // Buckets: slow ≤90 BPM · medium 91-120 · fast 121-150 · veryFast >150
  // 16 genres × 100+ verified YouTube backing tracks per genre with channel attribution.

  export type GenreVideo = { id: string; title: string; channel: string };
  export type TempoBucket = 'slow' | 'medium' | 'fast' | 'veryFast';
  export type GenreBuckets = Record<TempoBucket, GenreVideo[]>;

  /** Parse BPM from a YouTube title. Returns null if not found. */
  export function parseBpm(title: string): number | null {
    const patterns = [
      /(\d{2,3})\s*(?:bpm|BPM)/,
      /(?:bpm|BPM)\s*[:=]?\s*(\d{2,3})/,
      /(?:tempo|Tempo)\s*[:=]?\s*(\d{2,3})/,
      /\((\d{2,3})\s*bpm\)/i,
    ];
    for (const p of patterns) {
      const m = title.match(p);
      if (m) { const n = parseInt(m[1], 10); if (n >= 40 && n <= 280) return n; }
    }
    return null;
  }

  /** Bucket a BPM into tempo categories. Slow ≤90, Medium 91-120, Fast 121-150, Very Fast >150. */
  export function bpmToBucket(bpm: number | null): TempoBucket {
    if (bpm === null) return 'medium';
    if (bpm <= 90) return 'slow';
    if (bpm <= 120) return 'medium';
    if (bpm <= 150) return 'fast';
    return 'veryFast';
  }

  /** Heuristic tempo bucketing from title keywords when BPM not present. */
  export function bucketFromTitle(title: string): TempoBucket {
    const bpm = parseBpm(title);
    if (bpm !== null) return bpmToBucket(bpm);
    const t = title.toLowerCase();
    if (/\b(very fast|breakneck|blazing|frenetic)\b/.test(t)) return 'veryFast';
    if (/\b(burning|fast|uptempo|up-tempo|driving|intense|hard|energetic|rapid)\b/.test(t)) return 'fast';
    if (/\b(slow|ballad|relaxing|chill|mellow|sleepy|ambient|down-tempo|downtempo)\b/.test(t)) return 'slow';
    return 'medium';
  }

