  export const GENRES: readonly string[] = ['Blues', 'Jazz', 'Funk', 'Soul', 'R&B', 'Rock', 'Indie Rock', 'Pop', 'Country', 'Folk', 'Latin', 'Reggae', 'Hip Hop', 'Electronic', 'World', 'Cinematic'] as const;

  /** All available tempo buckets in display order. */
  export const TEMPO_BUCKETS: readonly TempoBucket[] = ['slow', 'medium', 'fast', 'veryFast'] as const;

  /** Display label for a tempo bucket. */
  export function tempoLabel(b: TempoBucket): string {
    return { slow: 'Slow (≤90 BPM)', medium: 'Medium (91-120)', fast: 'Fast (121-150)', veryFast: 'Very Fast (150+)' }[b];
  }

