  /** Get all videos for a genre across all tempo buckets. */
  export function getGenreAll(genre: string): GenreVideo[] {
    const b = GENRE_VIDEO_LIBRARY_BY_TEMPO[genre];
    if (!b) return [];
    return [...b.slow, ...b.medium, ...b.fast, ...b.veryFast];
  }

  /** Get videos for a genre filtered to a single tempo bucket. */
  export function getGenreByTempo(genre: string, bucket?: TempoBucket): GenreVideo[] {
    const b = GENRE_VIDEO_LIBRARY_BY_TEMPO[genre];
    if (!b) return [];
    if (!bucket) return getGenreAll(genre);
    return b[bucket];
  }

